import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const InspectionForm = () => {
  const navigate = useNavigate();
  const [inspectionData, setInspectionData] = useState({
    lotNumber: '',
    inspectionType: 'Receiving',
    inspector: '',
    fields: [],
    status: 'Pending',
    comments: ''
  });

  const [newField, setNewField] = useState({
    label: '',
    type: 'text',
    required: false,
    options: [],
    value: ''
  });

  const addField = () => {
    if (newField.label.trim()) {
      setInspectionData({
        ...inspectionData,
        fields: [...inspectionData.fields, { ...newField }]
      });
      setNewField({ label: '', type: 'text', required: false, options: [], value: '' });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post('http://localhost:5001/api/forms', inspectionData);
      navigate('/');
    } catch (error) {
      console.error('Error creating inspection:', error);
    }
  };

  const handleOptionsChange = (e) => {
    const options = e.target.value.split(',').map(opt => opt.trim());
    setNewField({ ...newField, options });
  };

  return (
    <div className="inspection-form">
      <h2>Create Quality Inspection</h2>
      <div className="form-section">
        <input
          type="text"
          placeholder="Lot Number"
          value={inspectionData.lotNumber}
          onChange={(e) => setInspectionData({ ...inspectionData, lotNumber: e.target.value })}
          className="form-input"
          required
        />
        <select
          value={inspectionData.inspectionType}
          onChange={(e) => setInspectionData({ ...inspectionData, inspectionType: e.target.value })}
          className="form-select"
          required
        >
          <option value="Receiving">Receiving</option>
          <option value="In-Process">In-Process</option>
          <option value="Final">Final</option>
        </select>
        <input
          type="text"
          placeholder="Inspector Name"
          value={inspectionData.inspector}
          onChange={(e) => setInspectionData({ ...inspectionData, inspector: e.target.value })}
          className="form-input"
          required
        />
      </div>

      <div className="field-creator">
        <h3>Add Inspection Point</h3>
        <div className="field-inputs">
          <input
            type="text"
            placeholder="Inspection Point Label"
            value={newField.label}
            onChange={(e) => setNewField({ ...newField, label: e.target.value })}
            className="form-input"
          />
          <select
            value={newField.type}
            onChange={(e) => setNewField({ ...newField, type: e.target.value })}
            className="form-select"
          >
            <option value="text">Text</option>
            <option value="number">Number</option>
            <option value="boolean">Pass/Fail</option>
            <option value="date">Date</option>
            <option value="select">Select</option>
          </select>
          {newField.type === 'select' && (
            <input
              type="text"
              placeholder="Options (comma-separated)"
              onChange={handleOptionsChange}
              className="form-input"
            />
          )}
          <label>
            <input
              type="checkbox"
              checked={newField.required}
              onChange={(e) => setNewField({ ...newField, required: e.target.checked })}
            />
            Required
          </label>
          <button onClick={addField} className="btn">Add Inspection Point</button>
        </div>
      </div>

      <div className="fields-preview">
        <h3>Inspection Points</h3>
        {inspectionData.fields.map((field, index) => (
          <div key={index} className="field-preview">
            <p>
              {field.label} ({field.type})
              {field.required ? ' *' : ''}
              {field.options?.length > 0 ? ` [${field.options.join(', ')}]` : ''}
            </p>
          </div>
        ))}
      </div>

      <div className="form-section">
        <textarea
          placeholder="Additional Comments"
          value={inspectionData.comments}
          onChange={(e) => setInspectionData({ ...inspectionData, comments: e.target.value })}
          className="form-textarea"
        />
      </div>

      <button onClick={handleSubmit} className="btn submit-btn">
        Create Inspection
      </button>
    </div>
  );
};

export default InspectionForm;
